"use strict";
var SeatType;
(function (SeatType) {
    SeatType[SeatType["Regular"] = 0] = "Regular";
    SeatType[SeatType["Premium"] = 1] = "Premium";
    SeatType[SeatType["VIP"] = 2] = "VIP";
})(SeatType || (SeatType = {}));
;
let ticket1 = [
    "sanam teri kasam",
    143,
    SeatType.VIP,
    899
];
function calculateDiscount(ticket) {
    if (ticket[2] == SeatType.VIP) {
        let res = ticket[3] - (ticket[3] * 0.20);
        return res;
    }
    else if (ticket[2] == SeatType.Premium) {
        let res = ticket[3] - (ticket[3] * 0.10);
        return res;
    }
    else {
        return ticket[3];
    }
}
console.log(calculateDiscount(ticket1));
console.log(ticket1);
